import React from 'react';
import { BarChart as RechartsBarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

const BarChart = ({ data }) => {
  const chartData = Object.keys(data).map(country => ({
    country,
    avgViews: Math.round(data[country].avgViews),
    videoCount: data[country].videoCount
  }));

  const formatNumber = (value) => {
    if (value >= 1e6) return `${(value / 1e6).toFixed(1)}M`;
    if (value >= 1e3) return `${(value / 1e3).toFixed(0)}K`;
    return value.toString();
  };

  const CustomTooltip = ({ active, payload, label }) => {
    if (active && payload && payload.length) {
      return (
        <div className="custom-tooltip">
          <p><strong>{label}</strong></p>
          <p>Avg Views: {formatNumber(payload[0].value)}</p>
          <p>Total Videos: {payload[0].payload.videoCount}</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div>
      <h2>Average Views by Country</h2>
      <div className="chart-container">
        <ResponsiveContainer width="100%" height="100%">
          <RechartsBarChart data={chartData} margin={{ top: 20, right: 30, bottom: 40, left: 80 }}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="country" />
            <YAxis tickFormatter={formatNumber} />
            <Tooltip content={<CustomTooltip />} />
            <Bar dataKey="avgViews" fill="#3498db" />
          </RechartsBarChart>
        </ResponsiveContainer>
      </div>
      <style jsx>{`
        .custom-tooltip {
          background: rgba(0, 0, 0, 0.8);
          color: white;
          padding: 10px;
          border-radius: 5px;
          font-size: 12px;
        }
      `}</style>
    </div>
  );
};

export default BarChart;
